"use client";
import { KeyboardEvent, useState } from "react";
import { motion, useReducedMotion } from "framer-motion";
const tabs=[['Observe','Collect the visible signals.'],['Frame','Name the decision boundary.'],['Decide','Record the next action.']];
export default function SignalCompassTabs(){const [active,setActive]=useState(0);const reduced=useReducedMotion();const onKey=(event:KeyboardEvent<HTMLButtonElement>,index:number)=>{let next=index;if(event.key==='ArrowRight')next=(index+1)%tabs.length;if(event.key==='ArrowLeft')next=(index+tabs.length-1)%tabs.length;if(event.key==='Home')next=0;if(event.key==='End')next=tabs.length-1;if(next!==index){event.preventDefault();setActive(next);}};return <section className="w-full max-w-sm rounded-[22px] border border-[#ececee] bg-white p-5 shadow-[0_10px_28px_rgba(17,17,17,.06)]"><div role="tablist" aria-label="Signal compass" className="relative grid grid-cols-3 gap-1">{tabs.map((tab,index)=><button key={tab[0]} id={`compass-tab-${index}`} role="tab" aria-selected={active===index} aria-controls="compass-panel" onClick={()=>setActive(index)} onKeyDown={(event)=>onKey(event,index)} className="min-h-11 rounded-xl px-1 text-xs font-extrabold text-[#111] outline-offset-3 focus-visible:outline focus-visible:outline-[3px] focus-visible:outline-[#111]">{tab[0]}</button>)}<motion.i aria-hidden className="absolute bottom-0 h-2 w-2 rounded-full bg-[#14b8c4]" animate={{x:`calc(${active*100}% + ${active===0?16:active===1?0:-16}px)`}} transition={reduced?{duration:0}:{type:"spring",stiffness:350,damping:27}}/></div><motion.div id="compass-panel" role="tabpanel" aria-labelledby={`compass-tab-${active}`} key={active} initial={{opacity:0}} animate={{opacity:1}} transition={{duration:reduced?.12:.15}} className="mt-4 rounded-2xl bg-[#f4f5f6] p-4"><p className="font-black text-[#111]">{tabs[active][0]}</p><p className="mt-1 text-sm text-[#4a4a4f]">{tabs[active][1]}</p></motion.div><p aria-live="polite" className="mt-3 text-xs text-[#4a4a4f]">{tabs[active][0]} selected.</p></section>}
